-- ============================================================
-- ADDED TABLE 2: AspNetRoles  (Admin, Staff, Donor)
-- ADDED TABLE 3: AspNetUserRoles (many-to-many)
-- Both generated by EF Core migrations automatically.
-- Roles to seed: Admin, Staff, Donor
-- ============================================================


-- ============================================================
-- INDEXES for common query patterns
-- ============================================================

CREATE INDEX ix_residents_safehouse     ON residents(safehouse_id);
CREATE INDEX ix_residents_status        ON residents(case_status);
CREATE INDEX ix_residents_risk          ON residents(current_risk_level);
CREATE INDEX ix_process_resident        ON process_recordings(resident_id, session_date);
CREATE INDEX ix_visitations_resident    ON home_visitations(resident_id, visit_date);
CREATE INDEX ix_education_resident      ON education_records(resident_id, record_date);
CREATE INDEX ix_health_resident         ON health_wellbeing_records(resident_id, record_date);
CREATE INDEX ix_interventions_resident  ON intervention_plans(resident_id, status);
CREATE INDEX ix_incidents_safehouse     ON incident_reports(safehouse_id, incident_date);
CREATE INDEX ix_donations_supporter     ON donations(supporter_id, donation_date);
CREATE INDEX ix_allocations_donation    ON donation_allocations(donation_id);
CREATE INDEX ix_allocations_safehouse   ON donation_allocations(safehouse_id);
CREATE INDEX ix_posts_platform          ON social_media_posts(platform, created_at);
CREATE INDEX ix_metrics_safehouse_month ON safehouse_monthly_metrics(safehouse_id, month_start);
